content:
{
  "sentences": [
    {
      "text": "請你把那本書拿來給我。",
      "pinyin": "Qǐng nǐ bǎ nà běn shū ná lái gěi wǒ.",
      "pinyin_numeric": "qing3 ni3 ba3 na4 ben3 shu1 na2 lai2 gei3 wo3",
      "translation_en": "Please bring that book to me.",
      "translation_ko": "그 책을 저에게 가져와 주세요."
    },
    {
      "text": "他把我的手機拿去了。",
      "pinyin": "Tā bǎ wǒ de shǒujī ná qù le.",
      "pinyin_numeric": "ta1 ba3 wo3 de shou3ji1 na2 qu4 le0",
      "translation_en": "He took my phone away.",
      "translation_ko": "그가 제 핸드폰을 가져갔어요."
    },
    {
      "text": "你什麼時候要把那杯咖啡拿來？",
      "pinyin": "Nǐ shénme shíhou yào bǎ nà bēi kāfēi ná lái?",
      "pinyin_numeric": "ni3 shen2me shi2hou yao4 ba3 na4 bei1 ka1fei1 na2 lai2",
      "translation_en": "When are you going to bring that cup of coffee?",
      "translation_ko": "그 커피를 언제 가져올 거예요?"
    },
    {
      "text": "請你把這本書拿回去給媽媽。",
      "pinyin": "Qǐng nǐ bǎ zhè běn shū ná huí qù gěi māma.",
      "pinyin_numeric": "qing3 ni3 ba3 zhe4 ben3 shu1 na2 hui2 qu4 gei3 ma1ma",
      "translation_en": "Please take this book back to Mom.",
      "translation_ko": "이 책을 엄마에게 다시 가져다 주세요."
    },
    {
      "text": "他已經把那個袋子拿回來了。",
      "pinyin": "Tā yǐjīng bǎ nà ge dàizi ná huí lái le.",
      "pinyin_numeric": "ta1 yi3jing1 ba3 na4 ge0 dai4zi na2 hui2 lai2 le0",
      "translation_en": "He has already brought that bag back.",
      "translation_ko": "그는 이미 그 가방을 다시 가져왔어요."
    },
    {
      "text": "你可以把這個便當拿去給客人嗎？",
      "pinyin": "Nǐ kěyǐ bǎ zhè ge biàndāng ná qù gěi kèrén ma?",
      "pinyin_numeric": "ni3 ke3yi3 ba3 zhe4 ge0 bian4dang1 na2 qu4 gei3 ke4ren2 ma0",
      "translation_en": "Can you take this bento to the customer?",
      "translation_ko": "이 도시락을 손님에게 가져다 줄 수 있나요?"
    },
    {
      "text": "他幫我把那杯水拿來了。",
      "pinyin": "Tā bāng wǒ bǎ nà bēi shuǐ ná lái le.",
      "pinyin_numeric": "ta1 bang1 wo3 ba3 na4 bei1 shui3 na2 lai2 le0",
      "translation_en": "He helped me bring that glass of water.",
      "translation_ko": "그가 저를 위해 그 물 한 잔을 가져왔어요."
    },
    {
      "text": "請你把這個盒子拿回去。",
      "pinyin": "Qǐng nǐ bǎ zhè ge hézi ná huí qù.",
      "pinyin_numeric": "qing3 ni3 ba3 zhe4 ge0 he2zi na2 hui2 qu4",
      "translation_en": "Please take this box back.",
      "translation_ko": "이 상자를 다시 가져가 주세요."
    },
    {
      "text": "他已經把那個東西拿來了。",
      "pinyin": "Tā yǐjīng bǎ nà ge dōngxi ná lái le.",
      "pinyin_numeric": "ta1 yi3jing1 ba3 na4 ge0 dong1xi na2 lai2 le0",
      "translation_en": "He has already brought that thing over.",
      "translation_ko": "그는 이미 그 물건을 가져왔어요."
    },
    {
      "text": "你可以把這本書拿去圖書館嗎？",
      "pinyin": "Nǐ kěyǐ bǎ zhè běn shū ná qù túshūguǎn ma?",
      "pinyin_numeric": "ni3 ke3yi3 ba3 zhe4 ben3 shu1 na2 qu4 tu2shu1guan3 ma0",
      "translation_en": "Can you take this book to the library?",
      "translation_ko": "이 책을 도서관에 가져갈 수 있나요?"
    }
  ]
}
